  static Rarity rarityFor(String? scientificName, String? commonName) {
    if (scientificName != null && scientificName.isNotEmpty) {
      final result = _byScientific[scientificName.trim().toLowerCase()];
      if (result != null) return result;
    }
    if (commonName != null && commonName.isNotEmpty) {
      final result = _byCommon[commonName.trim().toLowerCase()];
      if (result != null) return result;
    }
    return Rarity.common;
  }

  static bool isKnown(String? scientificName, String? commonName) {
    if (scientificName != null && scientificName.isNotEmpty) {
      if (_byScientific.containsKey(scientificName.trim().toLowerCase())) return true;
    }
    if (commonName != null && commonName.isNotEmpty) {
      if (_byCommon.containsKey(commonName.trim().toLowerCase())) return true;
    }
    return false;
  }
